export function financeIntegrationsRowKey(title) {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
}

function freezeResult(binding, result) {
  return Object.freeze({
    ...result,
    pack_id: binding.pack_id,
    program_id: FINANCE_INTEGRATIONS_PROGRAM_CONTRACT.program_id,
    source_external_integrations_i_pack_id: "CP00-693",
    ...FINANCE_INTEGRATIONS_NO_WRITE_ATTESTATION,
    no_write_attestation: FINANCE_INTEGRATIONS_NO_WRITE_ATTESTATION,
  });
}

