function createCaseSet(binding, requirements, caseSetId, sourceCaseSetId) {
  const sections = {};
  for (const [microId, titles] of Object.entries(requirements.required_section_rows)) {
    const rows = {};
    for (const title of titles) {
      const rowKey = financeIntegrationsRowKey(title);
      rows[rowKey] = Object.freeze({
        title,
        descriptor_only: true,
        runtime_execution: false,
        customer_safe_errors_only: true,
        raw_payload_included: false,
        external_credential_included: false,
        financial_payload_included: false,
        section_micro_phase_id: microId,
        ...(ROW_EXTRAS[rowKey] ?? {}),
      });
    }
    sections[microId] = Object.freeze({
      micro_phase_id: microId,
      micro_title: requirements.required_section_micro_titles[microId],
      row_count: titles.length,
      row_keys: Object.freeze(titles.map((title) => financeIntegrationsRowKey(title))),
      rows: Object.freeze(rows),
    });
  }
  return freezeResult(binding, { case_set_id: caseSetId, source_case_set_id: sourceCaseSetId, section_count: Object.keys(sections).length, sections: Object.freeze(sections) });
}

function createDescriptor(binding, requirements, descriptorName, caseSetField, caseSet, documentationEntry, handoffOpenScope, sourceDescriptor) {
  return freezeResult(binding, {
    descriptor: descriptorName,
    pack_binding: binding,
    program_contract: FINANCE_INTEGRATIONS_PROGRAM_CONTRACT,
    source_descriptor: sourceDescriptor,
    [caseSetField]: caseSet,
    public_exports: requirements.required_public_exports,
    documentation_entry: documentationEntry,
    index_export_check: true,
    no_leak_guards: requirements.required_no_leak_guards,
    authority_boundary: Object.freeze({
      claude_is_final_approval: false,
      local_validation_claims_enterprise_trust: false,
      human_final_approval_required_for_runtime_opening: true,
      runtime_opening_pack_id: binding.next_pack_id,
    }),
    hermes_packet: Object.freeze({ evidence_packet: "H23." + binding.pack_id + ".finance_integrations_" + descriptorName, gate: binding.hermes_gate, receipt_shape: "descriptor_only_finance_integrations_no_write" }),
    claude_packet: Object.freeze({ review_packet: "C23." + binding.pack_id + ".finance_integrations_" + descriptorName, gate: binding.claude_gate, read_only: true, source_inspection_basis: "read_tools_used", allowed_tools: requirements.allowed_claude_tools, invalid_review_blockers: requirements.forbidden_review_evidence }),
    closeout_handoff: Object.freeze({ from_pack_id: binding.pack_id, to_pack_id: binding.next_pack_id, next_subphase_id: binding.next_subphase_id, open_scope: handoffOpenScope }),
  });
}

