function createHermesEvidencePacket(binding, descriptor) { return freezeResult(binding, { evidence_packet: descriptor.hermes_packet.evidence_packet, gate: binding.hermes_gate, descriptor: descriptor.descriptor, receipt_shape: descriptor.hermes_packet.receipt_shape, writes_product_state: false, emits_runtime_receipt: false }); }
function createClaudeReviewPacket(binding, requirements, descriptor) { return freezeResult(binding, { review_packet: descriptor.claude_packet.review_packet, gate: binding.claude_gate, read_only: true, source_descriptor: descriptor.descriptor, allowed_tools: requirements.allowed_claude_tools, invalid_review_blockers: requirements.forbidden_review_evidence, review_questions: Object.freeze(["Does the descriptor remain no-write and runtime-closed?", "Are bank/card/WEHAGO/Douzone/tax/DART credentials and payloads excluded?", "Are permission and audit details customer-safe?", "Does the handoff preserve human authority for runtime opening?"]), blocks_pack_on_p0_p1_p2: true, promotes_claude_to_final_approval: false }); }
function createCloseoutHandoff(binding, descriptor) { return freezeResult(binding, { handoff_id: binding.pack_id + "-to-" + binding.next_pack_id, from_pack_id: binding.pack_id, to_pack_id: binding.next_pack_id, next_subphase_id: binding.next_subphase_id, source_descriptor: descriptor.descriptor, handoff_descriptor_only: true, open_questions: Object.freeze(["Continue RP23 External Integrations II from " + binding.next_subphase_id + ".", "Keep finance integration examples synthetic and credential-free.", "Keep Claude read-only, non-final, and bounded by hardened review receipt validation."]) }); }

